/**
 * @fileoverview Spinner constants.
 * @module module/Spinner/constants
 */

import { defineParts } from '../shared/definePart.js';

export const CLS = Object.freeze({
    ROOT:   'spinner',
    RING:   'spinner-ring',
    LABEL:  'spinner-label',
});

export const DEFAULTS = Object.freeze({
    size: 'md',
    variant: 'primary',
    label: null,
});

export const PART = defineParts('Spinner', {
    ROOT:    { class: 'spinner-container', aliases: ['root', 'container'] },
    RING:    { class: 'spinner-ring', aliases: ['ring'], tag: 'span' },
    LABEL:   { class: 'spinner-label', aliases: ['label'], tag: 'span' },
    SM_ROOT: { class: 'spinner-container-sm', aliases: ['sm'] },
    LG_ROOT: { class: 'spinner-container-lg', aliases: ['lg'] },
});

PART.ROOT.jit    = 'inline-flex flex-col items-center justify-center gap-[var(--sp-gap)]';
PART.RING.jit    = 'w-[var(--sp-size)] h-[var(--sp-size)] [border:var(--sp-thickness)_solid_var(--sp-track)] [border-top-color:var(--sp-color)] rounded-full [animation:rui-spin_0.7s_linear_infinite]';
PART.LABEL.jit   = 'text-[var(--sp-font-size)] fg-[var(--sp-label-color)]';
PART.SM_ROOT.jit = '[--sp-size:var(--sp-sm-size)] [--sp-thickness:var(--sp-sm-thickness)] [--sp-font-size:var(--sp-sm-font-size)]';
PART.LG_ROOT.jit = '[--sp-size:var(--sp-lg-size)] [--sp-thickness:var(--sp-lg-thickness)] [--sp-font-size:var(--sp-lg-font-size)]';
